"""htmlq - A command-line utility for querying HTML documents with CSS selectors."""

import sys
import argparse
from html.parser import HTMLParser
from urllib.parse import urljoin


VERSION = "htmlq 0.4.0"

# ─────────────────────── Node / DOM tree ───────────────────────

class Node:
    """A minimal DOM node that can be Element or TextNode."""
    __slots__ = ("tag", "attrs", "children", "text", "parent")

    def __init__(self, tag=None, attrs=None, text=None):
        self.tag = tag          # None for text nodes
        self.attrs = attrs or {}  # dict – attr name -> value
        self.children = []
        self.text = text        # only for text nodes
        self.parent = None

    def is_element(self):
        return self.tag is not None

    def __repr__(self):
        if self.tag is None:
            return f"Text({self.text!r})"
        kids = ",".join(repr(c) for c in self.children)
        return f"<{self.tag} {self.attrs} [{kids}]>"


# ─────────────────────── HTML Parser ───────────────────────

class DOMBuilder(HTMLParser):
    """Parse HTML into a tree of Node objects."""

    # Tags whose content is treated as raw text
    RAW_TAGS = {"script", "style"}
    # Void (self-closing) HTML5 tags
    VOID_TAGS = {
        "area", "base", "br", "col", "embed", "hr", "img", "input",
        "link", "meta", "param", "source", "track", "wbr",
    }

    def __init__(self):
        super().__init__(convert_charrefs=True)
        self.root = Node(tag="document")  # synthetic root
        self.current = self.root

    def _add_child(self, node):
        self.current.children.append(node)
        node.parent = self.current

    def handle_starttag(self, tag, attrs):
        node = Node(tag=tag, attrs=attrs)
        self._add_child(node)
        if tag not in self.VOID_TAGS or tag in self.RAW_TAGS:
            self.current = node

    def handle_endtag(self, tag):
        # Walk up the tree to find the matching open tag
        parent = self.current.parent
        while parent and parent.tag != tag:
            self.current.parent.children = self.current.parent.children[:-1]
            node_list = parent.parent.children
            while node_list and node_list[-1] != parent:
                node_list.pop()
            parent = parent.parent

        if parent is None:
            return  # Malformed – just ignore
        # Make sure siblings of the closed element are re-linked correctly
        self.current = parent

    def handle_data(self, data):
        node = Node(text=data)
        self._add_child(node)

    def handle_entityref(self, name):
        from html import entities
        try:
            char = entities.html5.get(name, f"&{name};")
        except Exception:
            char = f"&{name};"
        node = Node(text=char)
        self._add_child(node)

    def handle_charref(self, name):
        try:
            if name.startswith("x"):
                code = int(name[1:], 16)
            else:
                code = int(name)
            char = chr(code)
        except Exception:
            char = f"&#{name};"
        node = Node(text=char)
        self._add_child(node)

    def handle_comment(self, data):
        pass  # Ignore comments for simplicity

    def handle_decl(self, decl):
        pass

    def handle_pi(self, data):
        pass


def parse_html(html_str):
    """Parse an HTML string and return the root document node."""
    builder = DOMBuilder()
    builder.feed(html_str)
    return builder.root


# ─────────────────────── CSS Selector Parser ───────────────────────

class Selector:
    """A compiled CSS selector that can match Node objects."""
    def __init__(self):
        self.parts = []  # list of (combinator, simple_selector)

    def match(self, node):
        """Check whether a single node matches this selector."""
        cps = list(reversed(self.parts))
        if not cps:
            return True
        comb, ss = cps[0]
        if not ss._apply(node):
            return False
        return True


class SimpleSelector:
    """Represents a single simple selector part (tag, ids, classes, attrs)."""
    def __init__(self):
        self.tag = None       # tag name (lowercase) or None for *
        self.ids = set()
        self.classes = set()
        self.attrs = []      # list of (name, op, value) or (name,) for existence
        self.pseudo_classes = set()

    def _apply(self, node):
        if not node.is_element():
            return False
        ntag = node.tag.lower()
        if self.tag and self.tag != ntag:
            return False
        node_classes = set()
        node_ids = set()
        for k, v in node.attrs:
            if k.lower() == "class" and v:
                node_classes.update(v.lower().split())
            if k.lower() == "id" and v:
                node_ids.add(v.lower())
        if self.ids and not self.ids.issubset(node_ids):
            return False
        if self.classes and not self.classes.issubset(node_classes):
            return False
        # Check attribute selectors
        for attr_spec in self.attrs:
            aname = attr_spec[0].lower()
            found = False
            for k, v in node.attrs:
                if k.lower() == aname:
                    found = True
                    if len(attr_spec) == 1:
                        continue  # existence check passes
                    op = attr_spec[1]
                    val = attr_spec[2]
                    if op == "=":
                        if v != val:
                            found = False; break
                    elif op == "~=":
                        if val not in v.lower().split():
                            found = False; break
                    elif op == "|=":
                        if v.lower() != val.lower() and not v.lower().startswith(val.lower() + "-"):
                            found = False; break
                    elif op == "^=":
                        if not v.startswith(val):
                            found = False; break
                    elif op == "$=":
                        if not v.endswith(val):
                            found = False; break
                    elif op == "*=":
                        if val not in v:
                            found = False; break
                    elif op == "!=":
                        if v == val:
                            found = False; break
                    break
            if not found:
                return False
        return True


def parse_comma_list(sel_str):
    """Split a selector string by commas at the top level (respecting parens/quotes)."""
    selectors = []
    depth = 0
    current = []
    in_sq = False
    in_dq = False
    i = 0
    while i < len(sel_str):
        c = sel_str[i]
        if c == '"' and not in_sq:
            in_dq = not in_dq
        elif c == "'" and not in_dq:
            in_sq = not in_sq
        elif not in_sq and not in_dq:
            if c in '([{':
                depth += 1
            elif c in ')]}':
                depth -= 1
            elif c == ',' and depth == 0:
                s = ''.join(current).strip()
                if s:
                    selectors.append(s)
                current = []
                i += 1
                continue
        current.append(c)
        i += 1
    s = ''.join(current).strip()
    if s:
        selectors.append(s)
    return selectors


def parse_selector(sel_str):
    """Parse a simple CSS selector string into a SimpleSelector."""
    ss = SimpleSelector()
    s = sel_str.strip()
    if s == '':
        return ss

    # Process the string character by character
    i = 0
    while i < len(s):
        c = s[i]
        if c == '#':
            # ID selector
            j = i + 1
            while j < len(s) and (s[j].isalnum() or s[j] in '-_'):
                j += 1
            ss.ids.add(s[i+1:j].lower())
            i = j
        elif c == '.':
            # Class selector
            j = i + 1
            while j < len(s) and (s[j].isalnum() or s[j] in '-_'):
                j += 1
            ss.classes.add(s[i+1:j].lower())
            i = j
        elif c == '[':
            # Attribute selector
            j = s.index(']', i)
            attr_inner = s[i+1:j].strip()
            # Parse attribute selector
            if '=' in attr_inner:
                parts = attr_inner.split('=', 1)
                aname = parts[0].strip().lower()
                op_val = parts[1].strip()
                if op_val[0] in '^$*~|!':
                    op = op_val[0]
                    val = op_val[1:]
                    if val.startswith('"') and val.endswith('"'):
                        val = val[1:-1]
                    elif val.startswith("'") and val.endswith("'"):
                        val = val[1:-1]
                else:
                    op = '='
                    val = op_val
                    if val.startswith('"') and val.endswith('"'):
                        val = val[1:-1]
                    elif val.startswith("'") and val.endswith("'"):
                        val = val[1:-1]
                ss.attrs.append((aname, op, val))
            else:
                aname = attr_inner.strip().lower()
                ss.attrs.append((aname,))
            i = j + 1
        elif c.isalpha() or c == '*':
            # Tag name
            j = i
            while j < len(s) and (s[j].isalnum() or s[j] in '-_*'):
                j += 1
            tag = s[i:j]
            if tag != '*':
                ss.tag = tag.lower()
            i = j
        else:
            # Skip whitespace or other characters
            i += 1
    return ss


def parse_compound_selector(sel_str):
    """Parse a compound selector (possibly with descendant combinator) into a Selector."""
    if not sel_str.strip():
        return None

    # Split by whitespace (descendant combinator)
    parts = sel_str.strip().split()
    sel = Selector()
    for i, part in enumerate(parts):
        if not part:
            continue
        simple = parse_selector(part)
        combinator = 'descendant' if i > 0 else 'root'
        sel.parts.append((combinator, simple))
    return sel


def find_matching_nodes(document, compound_sel):
    """Find all nodes in the document that match a compound selector."""
    if not compound_sel or not compound_sel.parts:
        return [document]

    # Start from the rightmost part and work left
    results = _find_descendants(document, compound_sel.parts)
    return results


def _find_descendants(node, parts):
    """Recursively find nodes matching the compound selector parts."""
    if not parts:
        return [node]

    if not node.is_element():
        return []

    comb, simple = parts[-1]

    if not simple._apply(node):
        return []

    if len(parts) == 1:
        if comb == 'root':
            return [node]
        return [node]

    # Need to check ancestor chain for remaining parts
    remaining = parts[:-1]
    results = []
    # Walk up the tree to find ancestor matching remaining parts
    ancestor = node.parent
    child_found = False
    while ancestor:
        if not ancestor.is_element():
            ancestor = ancestor.parent
            continue
        child_results = _find_descendants(ancestor, remaining)
        if child_results:
            # Drop the matched ancestor; the remaining parts matched a higher ancestor
            # We found a valid chain, so this node matches
            results.append(node)
            child_found = True
            break
        ancestor = ancestor.parent

    return results


def find_elements(document, selectors_str):
    """Find all elements matching the selectors string."""
    all_selectors = parse_comma_list(selectors_str)
    results = []
    seen = set()
    for sel_str in all_selectors:
        compound = parse_compound_selector(sel_str)
        if not compound:
            continue
        matches = find_matching_nodes(document, compound)
        for m in matches:
            if m.is_element() and id(m) not in seen:
                seen.add(id(m))
                results.append(m)
    # Preserve document order by sorting
    results.sort(key=lambda n: _node_order(n))
    return results


_node_order_counter = 0
def _node_order(node):
    """Give a rough document order for sorting."""
    if hasattr(node, '_order'):
        return node._order
    return _get_order(node)

def _get_order(node):
    if hasattr(node, '_order'):
        return node._order
    # Walk to first ancestor that has an order, or set one
    return 0


def assign_node_orders(node, counter=0):
    """Assign document order to all nodes."""
    global _node_order_counter
    if node.is_element():
        node._order = counter[0]
        counter[0] += 1
    elif node.text is not None:
        node._order = counter[0]
        counter[0] += 1
    for child in node.children:
        assign_node_orders(child, counter)

def _node_order(node):
    if hasattr(node, '_order'):
        return node._order
    return 0


# ─────────────────────── Serialization ───────────────────────

HTML_VOID_ELEMENTS = {
    "area", "base", "br", "col", "embed", "hr", "img", "input",
    "link", "meta", "param", "source", "track", "wbr",
}

def html_escape(text):
    """Escape special HTML characters."""
    text = text.replace("&", "&amp;")
    text = text.replace("<", "&lt;")
    text = text.replace(">", "&gt;")
    text = text.replace('"', "&quot;")
    return text

def serialize_node(node, pretty=False, max_depth=0, depth=0):
    """Serialize a node to HTML string."""
    if not node.is_element():
        if node.text is not None:
            return html_escape(node.text)
        return ""

    tag = node.tag
    attrs_str = ""
    for k, v in node.attrs:
        if v is None:
            attrs_str += f" {k}"
        else:
            attrs_str += f' {k}="{html_escape(v)}"'

    if tag in HTML_VOID_ELEMENTS:
        return f"<{tag}{attrs_str}>"

    children_str = ""
    for child in node.children:
        children_str += serialize_node(child, pretty, max_depth, depth + 1)

    inner = children_str

    if pretty and depth < max_depth + 2:
        indent = "  " * (depth + 1)
        inner_indent = "  " * (depth + 2)
        lines = inner.strip().split('\n')
        formatted_lines = [inner_indent + l for l in lines]
        inner = '\n' + '\n'.join(formatted_lines) + '\n' + indent
        return f"{indent}<{tag}{attrs_str}>\n{inner}</{tag}>"

    return f"<{tag}{attrs_str}>{inner}</{tag}>"


def compute_max_depth(node):
    """Compute the max nesting depth of a node tree."""
    if not node.is_element():
        return 0
    if not node.children:
        return 0
    max_c = 0
    for c in node.children:
        d = compute_max_depth(c)
        if d > max_c:
            max_c = d
    return max_c + 1


def extract_text(node, ignore_whitespace=False):
    """Extract text content from a node tree."""
    parts = []
    for child in node.children:
        if child.is_element():
            parts.append(extract_text(child, ignore_whitespace))
        else:
            text = child.text if child.text else ""
            if ignore_whitespace and text.strip() == "":
                continue
            parts.append(text)
    return ''.join(parts)


def get_attribute(node, attr_name):
    """Get an attribute value from a node."""
    attr_name = attr_name.lower()
    for k, v in node.attrs:
        if k.lower() == attr_name:
            return v
    return None


# ─────────────────────── Base URL handling ───────────────────────

def get_base_url(document, default_base=None):
    """Find the base URL from <base> tag, or return default."""
    # Walk the tree to find <base href='...'>
    def find_base(node):
        if not node.is_element():
            return None
        if node.tag == 'base':
            for k, v in node.attrs:
                if k.lower() == 'href' and v:
                    return v
        for child in node.children:
            result = find_base(child)
            if result:
                return result
        return None

    base = find_base(document)
    if base:
        return base
    return default_base


def resolve_url(base_url, href):
    """Resolve a relative URL against a base URL."""
    if base_url:
        return urljoin(base_url, href)
    return href


# ─────────────────────── Remove nodes ───────────────────────

def remove_nodes(document, remove_selectors_strs):
    """Remove nodes matching the given selectors from the document tree."""
    for sel_str in remove_selectors_strs:
        all_selectors = parse_comma_list(sel_str)
        for sel in all_selectors:
            compound = parse_compound_selector(sel)
            if not compound:
                continue
            matches = find_matching_nodes(document, compound)
            for m in matches:
                if m.parent:
                    m.parent.children = [c for c in m.parent.children if c is not m]


# ─────────────────────── Main ───────────────────────

def main():
    global usage_string
    prog = "htmlq"

    usage_string = f"""{prog} 0.4.0
Michael Maclean <michael@mgdm.net>
Runs CSS selectors on HTML

USAGE:
    executable [FLAGS] [OPTIONS] [--] [selector]..."""

    parser = argparse.ArgumentParser(
        prog=prog,
        add_help=False,
        description="Runs CSS selectors on HTML",
    )
    parser.add_argument("selector", nargs="*", default=["html"])
    parser.add_argument("-t", "--text", action="store_true",
                        help="Output only the contents of text nodes inside selected elements")
    parser.add_argument("-p", "--pretty", action="store_true",
                        help="Pretty-print the serialised output")
    parser.add_argument("-w", "--ignore-whitespace", action="store_true",
                        help="When printing text nodes, ignore those that consist entirely of whitespace")
    parser.add_argument("-B", "--detect-base", action="store_true",
                        help="Try to detect the base URL from the <base> tag in the document")
    parser.add_argument("-a", "--attribute", dest="attribute", default=None,
                        help="Only return this attribute (if present) from selected elements")
    parser.add_argument("-b", "--base", dest="base_url", default=None,
                        help="Use this URL as the base for links")
    parser.add_argument("-f", "--filename", dest="filename", default=None,
                        help="The input file. Defaults to stdin")
    parser.add_argument("-o", "--output", dest="output", default=None,
                        help="The output file. Defaults to stdout")
    parser.add_argument("-r", "--remove-nodes", dest="remove_nodes_list", action="append", default=[],
                        help="Remove nodes matching this expression before output")
    parser.add_argument("-h", "--help", action="store_true")
    parser.add_argument("-V", "--version", action="store_true")

    args = parser.parse_args()

    if args.help:
        print(f"""htmlq 0.4.0
Michael Maclean <michael@mgdm.net>
Runs CSS selectors on HTML

USAGE:
    {sys.argv[0]} [FLAGS] [OPTIONS] [--] [selector]...

FLAGS:
    -B, --detect-base          Try to detect the base URL from the <base> tag in the document. If not found, default to
                               the value of --base, if supplied
    -h, --help                 Prints help information
    -w, --ignore-whitespace    When printing text nodes, ignore those that consist entirely of whitespace
    -p, --pretty               Pretty-print the serialised output
    -t, --text                 Output only the contents of text nodes inside selected elements
    -V, --version              Prints version information

OPTIONS:
    -a, --attribute <attribute>         Only return this attribute (if present) from selected elements
    -b, --base <base>                   Use this URL as the base for links
    -f, --filename <FILE>               The input file. Defaults to stdin
    -o, --output <FILE>                 The output file. Defaults to stdout
    -r, --remove-nodes <SELECTOR>...    Remove nodes matching this expression before output. May be specified multiple
                                        times

ARGS:
    <selector>...    The CSS expression to select [default: html]""")
        sys.exit(0)

    if args.version:
        print("htmlq 0.4.0")
        sys.exit(0)

    # Read input
    if args.filename:
        try:
            with open(args.filename, 'r') as f:
                html_str = f.read()
        except OSError as e:
            print(f"\nthread 'main' panicked:\nshould have opened input file: {e}", file=sys.stderr)
            sys.exit(101)
    else:
        html_str = sys.stdin.read()

    # Parse HTML
    document = parse_html(html_str)
    assign_node_orders(document)

    # Handle --detect-base
    if args.detect_base:
        base_from_doc = get_base_url(document)
        if base_from_doc:
            effective_base = base_from_doc
        else:
            effective_base = args.base_url
    else:
        effective_base = args.base_url

    # Remove nodes if requested
    if args.remove_nodes_list:
        remove_nodes(document, args.remove_nodes_list)

    # Combine selectors
    if len(args.selector) == 0:
        selector_str = "html"
    elif len(args.selector) == 1:
        selector_str = args.selector[0]
    else:
        # Multiple selectors - use comma-join
        selector_str = ", ".join(args.selector)

    # Find matching elements
    results = find_elements(document, selector_str)

    # Build output
    output_parts = []
    for node in results:
        if args.text:
            text = extract_text(node, args.ignore_whitespace)
            output_parts.append(text)
        elif args.attribute:
            val = get_attribute(node, args.attribute)
            if val is not None:
                if effective_base:
                    # Resolve URLs
                    val = resolve_url(effective_base, val)
                output_parts.append(val)
        else:
            out = serialize_node(node, args.pretty)
            output_parts.append(out)

    # Write output
    output_str = '\n'.join(output_parts)
    if output_str:
        output_str += '\n'

    if args.output:
        with open(args.output, 'w') as f:
            f.write(output_str)
    else:
        sys.stdout.write(output_str)

    sys.exit(0)


if __name__ == "__main__":
    main()
