    return None


# ─────────────────────── Base URL handling ───────────────────────

def get_base_url(document, default_base=None):
    """Find the base URL from <base> tag, or return default."""
    # Walk the tree to find <base href='...'>
    def find_base(node):
        if not node.is_element():
            return None
        if node.tag == 'base':
            for k, v in node.attrs:
                if k.lower() == 'href' and v:
                    return v
        for child in node.children:
            result = find_base(child)
            if result:
                return result
        return None

    base = find_base(document)
    if base:
        return base
    return default_base


def resolve_url(base_url, href):
    """Resolve a relative URL against a base URL."""
    if base_url:
        return urljoin(base_url, href)
    return href


# ─────────────────────── Remove nodes ───────────────────────

def remove_nodes(document, remove_selectors_strs):
    """Remove nodes matching the given selectors from the document tree."""
    for sel_str in remove_selectors_strs:
        all_selectors = parse_comma_list(sel_str)
