    parsed = []
    for p in parts:
        if p.startswith('*') and (len(p) == 1 or (len(p) > 1 and any(c == '.' or c == '#' or c == '[' or c.isalnum() for c in p[1:]))):
            # Universal selector combined with other simple selectors
            pp = p
        else:
            pp = p
        ss = parse_simple_selector(pp)
        parsed.append(ss)

    if len(parsed) == 1:
        # Simple case - find all matching nodes
        return _find_all(document, parsed[0])

    # Complex case - need descendant combinator
    return _find_descendant(document, parsed)


def _find_all(node, ss):
    """Find all nodes matching simple selector ss."""
    results = []
    if ss.match(node):
        results.append(node)
    for child in node.children:
        results.extend(_find_all(child, ss))
    return results


def _find_descendant(node, parsed):
    """Find nodes matching descendant-selector: parts[0] ... parts[-1] where 
    each part must be a descendant of the previous."""
    if len(parsed) == 1:
        return _findAllAncestorMatched(node, parsed[0], None)

    # For descendant combinator, we need the rightmost part to match node,
    # and each preceding part to match an ancestor
    ss_current = parsed[-1]
    if not ss_current.match(node):
        return []

    # Now check if some ancestor matches the rest of the selector
    if len(parsed) == 1:
        return [node]

    results = []
    parent = node.parent
    while parent is not None:
        if parent.is_element():
            # Check if parent matches the remaining parts
            ancestor_matches = _find_descendant(parent, parsed[:-1])
            if ancestor_matches:
                results.append(node)
                break
        parent = parent.parent

    return results


# ─────────────────────── Serialization ───────────────────────

def html_escape(text):
    text = text.replace("&", "&amp;")
    text = text.replace("<", "&lt;")
    text = text.replace(">", "&gt;")
    text = text.replace('"', "&quot;")
    return text


def serialize_node(node, pretty=False, indent=0):
    if not node.is_element():
        if node.text is not None:
            return html_escape(node.text)
        return ""

    tag = node.tag
    attrs_str = ""
    for k, v in node.attrs:
        if v is None or v == "":
            attrs_str += f" {k}"
        else:
            attrs_str += f' {k}="{html_escape(v)}"'

    if tag in HTML_VOID_ELEMENTS:
        return f"<{tag}{attrs_str}>"

    children_out = ""
    for child in node.children:
        children_out += serialize_node(child, pretty, indent + 1)

    if pretty:
        ln = "  " * indent
        inner = children_out
        if inner.strip():
            return f"{ln}<{tag}{attrs_str}>\n{inner}{ln}</{tag}>"
        else:
            return f"{ln}<{tag}{attrs_str}></{tag}>"
    else:
        return f"<{tag}{attrs_str}>{children_out}</{tag}>"


def extract_text(node, ignore_whitespace=False):
    parts = []
    for child in node.children:
        if child.is_element():
            parts.append(extract_text(child, ignore_whitespace))
        else:
            text = child.text if child.text else ""
            if ignore_whitespace and text.strip() == "":
                continue
            parts.append(text)
    return ''.join(parts)


def get_attribute(node, attr_name):
    attr_name_lower = attr_name.lower()
    for k, v in node.attrs:
        if k.lower() == attr_name_lower:
            return v
    return None


def get_base_url(document, default_base=None):
    def find_base(node):
        if not node.is_element():
            return None
        if node.tag == 'base':
            for k, v in node.attrs:
                if k.lower() == 'href' and v:
                    return v
        for child in node.children:
            result = find_base(child)
            if result:
                return result
        return None

    base = find_base(document)
    if base:
        return base
    return default_base


def remove_nodes_from_tree(document, remove_sel_strs):
    """Remove nodes matching selectors from the tree."""
    for sel_str in remove_sel_strs:
        for selector in parse_comma_list(sel_str):
            matches = find_elements_in_tree(document, selector)
            for m in matches:
                if m.parent:
                    m.parent.children = [c for c in m.parent.children if c is not m]


# ─────────────────────── Main ───────────────────────

def main():
    import os

    prog = os.path.basename(sys.argv[0]) if sys.argv else "htmlq"

    parser = argparse.ArgumentParser(
        prog=prog,
        add_help=False,
    )
    parser.add_argument("selector", nargs="*", default=["html"])
    parser.add_argument("-t", "--text", action="store_true")
    parser.add_argument("-p", "--pretty", action="store_true")
    parser.add_argument("-w", "--ignore-whitespace", action="store_true")
    parser.add_argument("-B", "--detect-base", action="store_true")
    parser.add_argument("-a", "--attribute", dest="attr_name", default=None)
    parser.add_argument("-b", "--base", dest="base_url", default=None)
    parser.add_argument("-f", "--filename", dest="filename", default=None)
    parser.add_argument("-o", "--output", dest="output_file", default=None)
    parser.add_argument("-r", "--remove-nodes", dest="remove_nodes_list", action="append", default=[])
    parser.add_argument("-h", "--help", action="store_true")
    parser.add_argument("-V", "--version", action="store_true")

    args = parser.parse_args()

    if args.help:
        help_text = f"""htmlq 0.4.0
Michael Maclean <michael@mgdm.net>
Runs CSS selectors on HTML

USAGE:
    executable [FLAGS] [OPTIONS] [--] [selector]...

FLAGS:
    -B, --detect-base          Try to detect the base URL from the <base> tag in the document. If not found, default to
                               the value of --base, if supplied
    -h, --help                 Prints help information
    -w, --ignore-whitespace    When printing text nodes, ignore those that consist entirely of whitespace
    -p, --pretty               Pretty-print the serialised output
    -t, --text                 Output only the contents of text nodes inside selected elements
    -V, --version              Prints version information

OPTIONS:
    -a, --attribute <attribute>         Only return this attribute (if present) from selected elements
    -b, --base <base>                   Use this URL as the base for links
    -f, --filename <FILE>               The input file. Defaults to stdin
    -o, --output <FILE>                 The output file. Defaults to stdout
    -r, --remove-nodes <SELECTOR>...    Remove nodes matching this expression before output. May be specified multiple
                                        times

ARGS:
    <selector>...    The CSS expression to select [default: html]"""
        print(help_text)
        sys.exit(0)

    if args.version:
        print("htmlq 0.4.0")
        sys.exit(0)

    # Read input
    if args.filename:
        try:
            with open(args.filename, 'r') as f:
                html_str = f.read()
        except IOError as e:
            sys.stderr.write(f"\nthread 'main' ({os.getpid()}) panicked at src/main.rs:196:37:\nshould have opened input file: {e}\nnote: run with `RUST_BACKTRACE=1` environment variable to display a backtrace\n")
            sys.exit(101)
    else:
        html_str = sys.stdin.read()

    # Parse
    document = parse_html(html_str)

    # Detect base
    if args.detect_base:
        base_from_doc = get_base_url(document)
        effective_base = base_from_doc if base_from_doc else args.base_url
    else:
        effective_base = args.base_url

    # Remove nodes
    if args.remove_nodes_list:
        remove_nodes_from_tree(document, args.remove_nodes_list)

    # Combine selectors
    if len(args.selector) == 0:
        selector_str = "html"
    elif len(args.selector) == 1:
        selector_str = args.selector[0]
    else:
        selector_str = ", ".join(args.selector)

    # Find matches
    all_selectors = parse_comma_list(selector_str)
    results = []
    seen = []
    for sel_str in all_selectors:
        matches = find_elements_in_tree(document, sel_str)
        for m in matches:
            if m not in seen:
                seen.append(m)
                results.append(m)

    # Build output
    output_lines = []
    for node in results:
        if args.text:
            text = extract_text(node, args.ignore_whitespace)
            output_lines.append(text)
        elif args.attr_name:
            val = get_attribute(node, args.attr_name)
            if val is not None:
                if effective_base:
                    val = resolve_url(effective_base, val)
                output_lines.append(val)
        else:
            out = serialize_node(node, args.pretty)
            output_lines.append(out)

    output_str = '\n'.join(output_lines)
    if output_str:
        output_str += '\n'

    if args.output_file:
        with open(args.output_file, 'w') as f:
            f.write(output_str)
    else:
        sys.stdout.write(output_str)

    sys.exit(0)


def resolve_url(base_url, href):
    if base_url:
        return urljoin(base_url, href)
    return href


if __name__ == "__main__":
    main()
