class DOMBuilder(HTMLParser):
    def __init__(self):
        super().__init__(convert_charrefs=True)
        self.root = Node(tag="document")
        self.current = self.root
        self.tag_stack = []

    def _add_child(self, node):
        self.current.children.append(node)
        node.parent = self.current

    def handle_starttag(self, tag, attrs):
        tag = tag.lower()
        node = Node(tag=tag, attrs=attrs)
        self._add_child(node)
        if tag not in HTML_VOID_ELEMENTS:
            self.current = node
            self.tag_stack.append(tag)

    def handle_endtag(self, tag):
        tag = tag.lower()
        # Walk up the stack to find matching tag
        for i in range(len(self.tag_stack) - 1, -1, -1):
            if self.tag_stack[i] == tag:
                # Pop everything up to and including this tag
                self.tag_stack = self.tag_stack[:i]
                if self.tag_stack:
                    # We need to find which node corresponds to tag_stack[-1]
                    # Walk up from current
                    n = self.current
                    while n and n.tag != self.tag_stack[-1]:
                        n = n.parent
                    if n:
                        self.current = n
                    return
                else:
                    self.current = self.root
                return
        # Tag not found in stack - ignore

    def handle_data(self, data):
        node = Node(text=data)
        self._add_child(node)

    def handle_entityref(self, name):
        import html.entities
        char = html.entities.html5.get(name, f"&{name};")
        node = Node(text=char)
        self._add_child(node)

    def handle_charref(self, name):
        try:
            if name.startswith("x"):
                code = int(name[1:], 16)
            else:
                code = int(name)
            char = chr(code)
        except Exception:
            char = f"&#{name};"
        node = Node(text=char)
        self._add_child(node)


def parse_html(html_str):
    builder = DOMBuilder()
    try:
        builder.feed(html_str)
    except Exception:
        pass
    return builder.root


# ─────────────────────── CSS Selector Parser ───────────────────────

class SimpleSelector:
    def __init__(self):
        self.tag = None
        self.ids = set()
        self.classes = set()
        self.attrs = []

    def match(self, node):
        if not node.is_element():
            return False
        ntag = node.tag.lower() if node.tag else ""
        if self.tag is not None and self.tag != ntag:
            return False
        node_classes = set()
        node_ids = set()
        for k, v in node.attrs:
            if k.lower() == "class" and v:
                node_classes.update(v.lower().split())
            if k.lower() == "id" and v:
                node_ids.add(v.lower())
        if self.ids and not self.ids.issubset(node_ids):
            return False
        if self.classes and not self.classes.issubset(node_classes):
            return False
        for attr_spec in self.attrs:
            aname = attr_spec[0].lower()
            found = False
            for k, v in node.attrs:
                if k.lower() == aname:
                    found = True
                    if len(attr_spec) == 1:
                        continue
                    op = attr_spec[1]
                    val = attr_spec[2]
                    ni = attr_spec[3]
                    if op == "=":
                        if ni:
                            if v.lower() != val.lower():
                                found = False; break
                        else:
                            if v != val:
                                found = False; break
                    elif op == "~=":
                        if ni:
                            if val.lower() not in v.lower().split():
                                found = False; break
                        else:
                            if val not in v.split():
                                found = False; break
                    elif op == "|=":
                        if ni:
                            if v.lower() != val.lower() and not v.lower().startswith(val.lower() + "-"):
                                found = False; break
                        else:
                            if v != val and not v.startswith(val + "-"):
                                found = False; break
                    elif op == "^=":
                        if ni:
                            if not v.lower().startswith(val.lower()):
                                found = False; break
                        else:
                            if not v.startswith(val):
                                found = False; break
                    elif op == "$=":
                        if ni:
                            if not v.lower().endswith(val.lower()):
                                found = False; break
                        else:
                            if not v.endswith(val):
                                found = False; break
                    elif op == "*=":
                        if ni:
                            if val.lower() not in v.lower():
                                found = False; break
                        else:
                            if val not in v:
                                found = False; break
                    elif op == "!=":
                        if ni:
                            if v.lower() == val.lower():
                                found = False; break
                        else:
                            if v == val:
                                found = False; break
                    break
            if not found:
                return False
        return True


def parse_comma_list(sel_str):
    selectors = []
    depth = 0
    current = []
    in_sq = False
    in_dq = False
    i = 0
    while i < len(sel_str):
        c = sel_str[i]
        if c == '"' and not in_sq:
            in_dq = not in_dq
        elif c == "'" and not in_dq:
            in_sq = not in_sq
        elif not in_sq and not in_dq:
            if c in '([{':
                depth += 1
            elif c in ')]}':
                depth -= 1
            elif c == ',' and depth == 0:
                s = ''.join(current).strip()
                if s:
                    selectors.append(s)
                current = []
                i += 1
                continue
        current.append(c)
        i += 1
    s = ''.join(current).strip()
    if s:
        selectors.append(s)
    return selectors


def parse_attribute_selector(s):
    """Parse an attribute selector like [attr], [attr=val], [attr~=val], etc."""
    s = s.strip()
    if not s:
        return None, None, None, False

    # Check for case-insensitivity flag (i)
    ni = False
    if ' i' in s:
        s = s[:s.rfind(' i')]
        ni = True

    for op in ['~=', '|=', '!=', '^=', '$=', '*=', '=']:
        idx = s.find(op)
        if idx >= 0:
            aname = s[:idx].strip().lower()
            raw_val = s[idx+len(op):].strip()
            # Unquote
            if (raw_val.startswith('"') and raw_val.endswith('"')) or \
               (raw_val.startswith("'") and raw_val.endswith("'")):
                raw_val = raw_val[1:-1]
            return aname, op, raw_val, ni

    # Just an attribute name (existence check)
    return s.strip().lower(), None, None, False


def parse_simple_selector(tok):
    """Parse a single simple selector token (no combinators)."""
    ss = SimpleSelector()
    s = tok
    i = 0
    while i < len(s):
        c = s[i]
        if c == '#':
            j = i + 1
            while j < len(s) and (s[j].isalnum() or s[j] in '-_.'):
                j += 1
            if j > i + 1:
                ss.ids.add(s[i+1:j].lower())
            i = j
        elif c == '.':
            j = i + 1
            while j < len(s) and (s[j].isalnum() or s[j] in '-_.'):
                j += 1
            if j > i + 1:
                ss.classes.add(s[i+1:j].lower())
            i = j
        elif c == '[':
            # Find matching ]
            depth = 1
            j = i + 1
            while j < len(s) and depth > 0:
                if s[j] == '[':
                    depth += 1
                elif s[j] == ']':
                    depth -= 1
                j += 1
            attr_str = s[i+1:j-1]
            aname, op, val, ni = parse_attribute_selector(attr_str)
            if op is not None:
                ss.attrs.append((aname, op, val, ni))
            else:
                ss.attrs.append((aname,))
            i = j
        elif c == '*':
            i += 1  # Universal selector - matches anything
        elif c.isalpha() or c == '_':
            j = i
            while j < len(s) and (s[j].isalnum() or s[j] in '-_.'):
                j += 1
            name = s[i:j]
            if ss.tag is None:
                ss.tag = name.lower()
            i = j
        else:
            i += 1
    return ss


def find_elements_in_tree(document, selector_str):
    """Find all elements matching a compound selector (with descendant combinator)."""
    # Split by descendant combinator (whitespace)
    parts = selector_str.strip().split()
    if not parts:
        return []

    parsed = []
    for p in parts:
        if p.startswith('*') and (len(p) == 1 or (len(p) > 1 and any(c == '.' or c == '#' or c == '[' or c.isalnum() for c in p[1:]))):
            # Universal selector combined with other simple selectors
            pp = p
        else:
            pp = p
        ss = parse_simple_selector(pp)
        parsed.append(ss)

    if len(parsed) == 1:
        # Simple case - find all matching nodes
        return _find_all(document, parsed[0])

    # Complex case - need descendant combinator
    return _find_descendant(document, parsed)


def _find_all(node, ss):
    """Find all nodes matching simple selector ss."""
    results = []
    if ss.match(node):
        results.append(node)
    for child in node.children:
        results.extend(_find_all(child, ss))
    return results


def _find_descendant(node, parsed):
    """Find nodes matching descendant-selector: parts[0] ... parts[-1] where 
    each part must be a descendant of the previous."""
    if len(parsed) == 1:
        return _findAllAncestorMatched(node, parsed[0], None)

    # For descendant combinator, we need the rightmost part to match node,
    # and each preceding part to match an ancestor
    ss_current = parsed[-1]
    if not ss_current.match(node):
        return []

    # Now check if some ancestor matches the rest of the selector
    if len(parsed) == 1:
        return [node]

    results = []
    parent = node.parent
    while parent is not None:
        if parent.is_element():
            # Check if parent matches the remaining parts
            ancestor_matches = _find_descendant(parent, parsed[:-1])
            if ancestor_matches:
                results.append(node)
                break
        parent = parent.parent

    return results


# ─────────────────────── Serialization ───────────────────────

def html_escape(text):
    text = text.replace("&", "&amp;")
    text = text.replace("<", "&lt;")
    text = text.replace(">", "&gt;")
    text = text.replace('"', "&quot;")
    return text


def serialize_node(node, pretty=False, indent=0):
    if not node.is_element():
        if node.text is not None:
            return html_escape(node.text)
        return ""

    tag = node.tag
    attrs_str = ""
    for k, v in node.attrs:
        if v is None or v == "":
            attrs_str += f" {k}"
        else:
            attrs_str += f' {k}="{html_escape(v)}"'

    if tag in HTML_VOID_ELEMENTS:
        return f"<{tag}{attrs_str}>"

    children_out = ""
    for child in node.children:
        children_out += serialize_node(child, pretty, indent + 1)

    if pretty:
        ln = "  " * indent
        inner = children_out
        if inner.strip():
            return f"{ln}<{tag}{attrs_str}>\n{inner}{ln}</{tag}>"
        else:
            return f"{ln}<{tag}{attrs_str}></{tag}>"
    else:
        return f"<{tag}{attrs_str}>{children_out}</{tag}>"


def extract_text(node, ignore_whitespace=False):
    parts = []
    for child in node.children:
        if child.is_element():
            parts.append(extract_text(child, ignore_whitespace))
        else:
            text = child.text if child.text else ""
            if ignore_whitespace and text.strip() == "":
                continue
            parts.append(text)
    return ''.join(parts)


def get_attribute(node, attr_name):
    attr_name_lower = attr_name.lower()
    for k, v in node.attrs:
        if k.lower() == attr_name_lower:
            return v
    return None


def get_base_url(document, default_base=None):
    def find_base(node):
        if not node.is_element():
            return None
        if node.tag == 'base':
            for k, v in node.attrs:
                if k.lower() == 'href' and v:
                    return v
        for child in node.children:
            result = find_base(child)
            if result:
                return result
        return None

    base = find_base(document)
    if base:
        return base
    return default_base


def remove_nodes_from_tree(document, remove_sel_strs):
    """Remove nodes matching selectors from the tree."""
    for sel_str in remove_sel_strs:
        for selector in parse_comma_list(sel_str):
            matches = find_elements_in_tree(document, selector)
            for m in matches:
                if m.parent:
                    m.parent.children = [c for c in m.parent.children if c is not m]


# ─────────────────────── Main ───────────────────────

def main():
    import os

    prog = os.path.basename(sys.argv[0]) if sys.argv else "htmlq"

    parser = argparse.ArgumentParser(
        prog=prog,
        add_help=False,
    )
    parser.add_argument("selector", nargs="*", default=["html"])
    parser.add_argument("-t", "--text", action="store_true")
    parser.add_argument("-p", "--pretty", action="store_true")
    parser.add_argument("-w", "--ignore-whitespace", action="store_true")
    parser.add_argument("-B", "--detect-base", action="store_true")
