# ─────────────────────── CSS Selector Engine ───────────────────────

class SimpleSelector:
    """A simple selector (tag + ids + classes + attr predicates)."""
    def __init__(self):
        self.tag = None
        self.ids = set()
        self.classes = set()
        self.attr_checks = []  # list of (name, op, value, case_insensitive)
        self.is_universal = False

    def match(self, node):
        if not node.is_element():
            return False
        ntag = node.tag.lower()
        if self.tag is not None and self.tag != ntag:
            return False
        # Gather classes and ids
        node_classes = set()
        for k, v in node.attrs:
            if k.lower() == "class" and v:
                node_classes.update(tc.strip().lower() for tc in v.split() if tc.strip())
            if k.lower() == "id":
                self.node_id = v.lower()
        # Check ids
        if self.ids:
            node_id = None
            for k, v in node.attrs:
                if k.lower() == "id":
                    node_id = v.lower()
                    break
            if not node_id or not self.ids.issubset([node_id]):
                return False
        if self.classes and not self.classes.issubset(node_classes):
            return False
        # Check attribute selectors
        for check in self.attr_checks:
            cname = check[0]
            if len(check) == 1:
                # Existence check
                if not any(k.lower() == cname for k, _ in node.attrs):
                    return False
                continue
            op = check[1]
            val = check[2]
            casei = check[3] if len(check) > 3 else False
            aval = None
            for k, v in node.attrs:
                if k.lower() == cname:
                    aval = v
                    break
            if aval is None:
                if op != "!=":
                    return False
                continue
            if casei:
                aval = aval.lower()
                val = val.lower()
            if op == "=" and aval != val:
                return False
            elif op == "~=" and val not in aval.split():
                return False
            elif op == "|=" and (aval != val and not aval.startswith(val + "-")):
                return False
            elif op == "^=" and not aval.startswith(val):
                return False
            elif op == "$=" and not aval.endswith(val):
                return False
            elif op == "*=" and val not in aval:
                return False
            elif op == "!=" and aval == val:
                return False
        return True


def _tokenize_attr(s):
    """Parse attribute selector content, return (name, op, value, case_insensitive)."""
    s = s.strip()
    if not s:
        return None, None, None, False
    # Check case insensitive flag
    case_insensitive = False
    if s.endswith(' i'):
        case_insensitive = True
        s = s[:-2].strip()
    elif s.endswith(' I'):
        case_insensitive = True
        s = s[:-2].strip()
    # Find operator
    for op in ['~=', '|=', '!=', '^=', '$=', '*=', '=']:
        idx = s.find(op)
        if idx >= 0:
            name = s[:idx].strip().lower()
            raw_val = s[idx + len(op):].strip()
            # Unquote
            raw_val = raw_val.strip()
            if len(raw_val) >= 2 and ((raw_val[0] == '"' and raw_val[-1] == '"') or
                                       (raw_val[0] == "'" and raw_val[-1] == "'")):
                raw_val = raw_val[1:-1]
            return name, op, raw_val, case_insensitive
    # Existence check
    return s.strip().lower(), None, None, False


def parse_simple_selector(token):
    """Parse a single compound simple selector token (no combinators)."""
    ss = SimpleSelector()
    s = token
    i = 0
    while i < len(s):
        c = s[i]
        if c == '#':
            j = i + 1
            while j < len(s) and (s[j].isalnum() or s[j] in '-_@'):
                j += 1
            if j > i + 1:
                ss.ids.add(s[i+1:j].lower())
            i = j
        elif c == '.':
            j = i + 1
            while j < len(s) and (s[j].isalnum() or s[j] in '-_@'):
                j += 1
            if j > i + 1:
                ss.classes.add(s[i+1:j].lower())
            i = j
        elif c == '[':
            depth = 1
            j = i + 1
            while j < len(s) and depth > 0:
                if s[j] == '[': depth += 1
                elif s[j] == ']': depth -= 1
                j += 1
            inner = s[i+1:j-1]
            name, op, val, casei = _tokenize_attr(inner)
            if op is not None:
                ss.attr_checks.append((name, op, val, casei))
            else:
                ss.attr_checks.append((name,))
            i = j
        elif c == '*':
            ss.is_universal = True
            i += 1
        elif c in '.@' or c.isalnum():
            j = i
            while j < len(s) and (s[j].isalnum() or s[j] in '-_@'):
                j += 1
            part = s[i:j]
            if ss.tag is None:
                ss.tag = part.lower()
            i = j
        else:
            i += 1
    return ss


def find_all_matching(document, ss):
    """Find all nodes matching a simple selector."""
    results = []
    def walk(node):
        if node.is_element() and ss.match(node):
            results.append(node)
        for child in node.children:
            walk(child)
    walk(document)
    return results


def find_compound_selector(document, compound_parts):
    """Find nodes matching a compound selector (with descendant combinator spaces)."""
    if not compound_parts:
        return [document]
    parts = compound_parts.split()
    if not parts:
        return []

    sels = [parse_simple_selector(p) for p in parts]

    if len(sels) == 1:
        return find_all_matching(document, sels[0])

    # For descendant combinator: find ancestors matching preceding parts,
    # then check if current node matches the last part
    return _descendant_match(document, sels, 0)


def _descendant_match(document, sels, sel_idx):
    """Match a compound selector from left to right using descendant combinator."""
    if sel_idx >= len(sels):
        return [document]

    results = []
    ss_current = sels[sel_idx]

    if sel_idx == 0:
        # For the first part, just find all matching
        matches = find_all_matching(document, ss_current)
        for m in matches:
            for sub in _descendant_match(document, sels, sel_idx + 1):
                # Need to check if any descendant of m matches remaining selectors
                if _has_descendant_match(m, sels, sel_idx + 1):
                    # The descendants of m that match the rest
                    results.extend(_descendant_match(m, sels, sel_idx + 1))
                    # Also m itself if there are no more selectors
                    if sel_idx + 1 >= len(sels):
                        pass  # Already handled by find_all_matching above
        # Actually let me redo this more carefully
        pass

    return results


def _has_descendant_match(node, sels, idx):
    """Check if node has any descendant matching remaining selectors."""
    if idx >= len(sels):
        return True
    ss = sels[idx]
    for child in node.children:
        if child.is_element() and ss.match(child):
            if _has_descendant_match(child, sels, idx + 1):
                return True
    return False


def find_elements(document, selector_str):
    """Main entry: parse selector(s) and return matching elements in document order."""
    comma_parts = _split_comma(selector_str)
    results = []
    seen = set()
    for part in comma_parts:
        matches = _find_compound(document, part.strip())
        for m in matches:
            if m not in seen:
                seen.add(m)
                results.append(m)
    # Sort by document order
    results.sort(key=lambda n: _doc_order(n))
    return results


_doc_order_counter = [0]

def assign_orders(node):
    _assign_orders(node, _doc_order_counter)

def _assign_orders(node, counter):
    if node.is_element():
        node._order = counter[0]
        counter[0] += 1
    for child in node.children:
        _assign_orders(child, counter)

def _doc_order(node):
    return getattr(node, '_order', 0)


def _split_comma(s):
    """Split selector by commas at top level."""
    parts = []
    depth = 0
    buf = []
    in_sq = in_dq = False
    for i, c in enumerate(s):
        if c == '"' and not in_sq: in_dq = not in_dq
        elif c == "'" and not in_dq: in_sq = not in_sq
        elif not in_sq and not in_dq:
            if c in '([{': depth += 1
            elif c in ')]}': depth -= 1
            elif c == ',' and depth == 0:
                parts.append(''.join(buf).strip())
                buf = []
                continue
        buf.append(c)
    rest = ''.join(buf).strip()
    if rest:
        parts.append(rest)
    return parts


def _parse_compound(part):
    """Parse a compound selector part (space-separated simple selectors)."""
    # Split by spaces/resolution, respecting brackets and quotes
    tokens = []
    depth = 0
    buf = []
    in_sq = in_dq = False
    for c in part:
        if c == '"' and not in_sq: in_dq = not in_dq
        elif c == "'" and not in_dq: in_sq = not in_sq
        elif not in_sq and not in_dq:
            if c in '([{': depth += 1
            elif c in ')]}': depth -= 1
            elif c == ' ' and depth == 0:
                t = ''.join(buf).strip()
                if t:
                    tokens.append(t)
                buf = []
                continue
        buf.append(c)
    t = ''.join(buf).strip()
    if t:
        tokens.append(t)
    return [parse_simple_selector(tok) for tok in tokens]


def _find_compound(document, compound_str):
    """Find elements matching a compound selector string."""
    sels = _parse_compound(compound_str)
    if not sels:
        return []
    if len(sels) == 1:
        return find_all_matching(document, sels[0])

    # For descendant combinator: 
    # Start from elements matching the first selector,
    # then check if they have descendants matching the rest
    matches_first = find_all_matching(document, sels[0])
    results = []
    for m in matches_first:
        results.extend(_descendant_find(m, sels[1:]))
    return results


def _descendant_find(ancestor, remaining_sels):
    """Find descendants of ancestor matching remaining_sels chain."""
    if not remaining_sels:
        return [ancestor]

    ss = remaining_sels[0]
    results = []

    for child in ancestor.children:
        if child.is_element() and ss.match(child):
            if len(remaining_sels) == 1:
                results.append(child)
            else:
                results.extend(_descendant_find(child, remaining_sels[1:]))

    return results


# ─────────────────────── Serialization ───────────────────────

esc_table = str.maketrans({
    '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;'
})

def html_escape(text):
    return text.translate(esc_table)


def serialize(node, pretty=False):
    """Serialize a node to HTML string."""
    if not node.is_element():
        if node.text is not None:
            return html_escape(node.text)
        return ""

    tag = node.tag
    attrs_str = ""
    for k, v in node.attrs:
        if v is None:
            attrs_str += " " + k
        # Serialize special attributes in certain contexts
        if tag == "script" and k == "type":
            attrs_str += f' type="{v}"'
        else:
            attrs_str += ' {}="{}"'.format(k, str(v).translate(esc_table))

    # Check if any children exist
    has_children = bool(node.children)
    has_real_children = any(c.is_element() or (c.text and c.text.strip()) for c in node.children)

    if tag in HTML_VOID_ELEMENTS:
        return "<{}{}>".format(tag, attrs_str)

    if not has_children:
        if pretty:
            if tag in BLOCK_ELEMENTS:
                ln = ""
                return "{}<{}{}</{}>".format(ln, tag, attrs_str, tag)
            else:
                return "<{}{}</{}>".format(tag, attrs_str, tag)
        return "<{}{}</{}>".format(tag, attrs_str, tag)

    inner = ""
    for child in node.children:
        inner += serialize(child, pretty)

    if pretty:
        return _serialize_pretty(tag, attrs_str, inner)

    return "<{}{}{}>{}</{}>".format(tag, attrs_str, "", inner, tag)


def _serialize_pretty(tag, attrs_str, inner, indent_level=0):
    """Pretty-print serialization matching the original output."""
    indent = "\n  " * indent_level
    if tag in BLOCK_ELEMENTS:
        if indent_level > 0:
            pre = indent
        else:
            pre = "\n"
        lead = "  " * indent_level
        if tag in HTML_VOID_ELEMENTS:
            return "{}<{}{}/>".format(pre, tag, attrs_str)
        if inner.strip():
            return "{}<{}{}>\n{}{}\n{}{}</{}>".format(
                pre, tag, attrs_str, lead, _indent_block(inner, indent_level + 1), 
                pre, tag)
        else:
            return "{}<{}{}</{}>".format(pre, tag, attrs_str, tag)
    else:
        if indent_level > 0:
            pre = "  " * indent_level
        else:
            pre = ""
        return "<{}{}{}>{}</{}>".format(tag, attrs_str, "", inner, tag)


def _indent_block(text, level):
    """Add indentation to text."""
    return text  # Simplified for now
    lines = text.split('\n')
    indent = "  " * level
    return '\n'.join(indent + l if l.strip() or l == "" else indent + l for l in lines)


# ─────────────────────── Text extraction ───────────────────────

def extract_text(node, ignore_ws=False):
    parts = []
    for child in node.children:
        if child.is_element():
            parts.append(extract_text(child, ignore_ws))
        else:
            t = child.text if child.text else ""
            if ignore_ws and not t.strip():
                continue
            parts.append(t)
    return ''.join(parts)


# ─────────────────────── Attribute ───────────────────────

def get_attr(node, name):
    name = name.lower()
    for k, v in node.attrs:
        if k.lower() == name:
            return v
    return None


# ─────────────────────── Base URL ───────────────────────

def find_base(document):
    def walk(node):
        if not node.is_element():
            return None
        if node.tag == 'base':
            for k, v in node.attrs:
                if k.lower() == 'href' and v:
                    return v
        for child in node.children:
            r = walk(child)
            if r:
                return r
        return None
    return walk(document)


def resolve_url(base, href):
    if base:
        return urljoin(base, href)
    return href


# ─────────────────────── Remove nodes ───────────────────────

def remove_matching(document, remove_selector_strs):
    for sel_str in remove_selector_strs:
        comma_parts = _split_comma(sel_str)
        for cp in comma_parts:
            matches = _find_compound(document, cp.strip())
            for m in matches:
                if m.parent:
                    m.parent.children = [c for c in m.parent.children if c is not m]


# ─────────────────────── Main ───────────────────────

def main():
    pid = os.getpid()
    pgm = os.path.basename(sys.argv[0]) if sys.argv else sys.argv[0]

    # Simple arg parsing ourselves to handle all edge cases
    args = sys.argv[1:]

    # Parse arguments
    selectors = []
    text_flag = False
    pretty_flag = False
    ignore_ws = False
    detect_base = False
    attr_name = None
    base_url = None
    filename = None
    output_file = None
    remove_sels = []

    i = 0
    while i < len(args):
        a = args[i]
        if a in ('-h', '--help'):
            _print_help(pgm)
            sys.exit(0)
        elif a in ('-V', '--version'):
            print(VERSION_STR)
            sys.exit(0)
        elif a in ('-t', '--text'):
            text_flag = True
        elif a in ('-p', '--pretty'):
