        elif a in ('-w', '--ignore-whitespace'):
            ignore_ws = True
        elif a in ('-B', '--detect-base'):
            detect_base = True
        elif a in ('-a', '--attribute'):
            i += 1
            attr_name = args[i]
        elif a in ('-b', '--base'):
            i += 1
            base_url = args[i]
        elif a in ('-f', '--filename'):
            i += 1
            filename = args[i]
        elif a in ('-o', '--output'):
            i += 1
            output_file = args[i]
        elif a in ('-r', '--remove-nodes'):
            i += 1
            remove_sels.append(args[i])
        elif a == '--':
            # Everything after -- is a selector
            i += 1
            selectors.extend(args[i:])
            break
        else:
            selectors.append(a)
        i += 1

    # Input selector string
    if not selectors:
        selector_str = "html"
    else:
        selector_str = ", ".join(selectors)

    # Read input
    if filename:
        try:
            with open(filename, 'r') as f:
                html_str = f.read()
        except OSError as e:
            sys.stderr.write(
                "\nthread 'main' ({}) panicked at src/main.rs:196:37:\n"
                "should have opened input file: {}\n"
                "note: run with `RUST_BACKTRACE=1` environment variable to display a backtrace\n"
                .format(pid, e)
            )
            sys.exit(101)
    else:
        html_str = sys.stdin.read()

    # Parse
    document = parse_html(html_str)

    # Detect base
    if detect_base:
        doc_base = find_base(document)
        eff_base = doc_base if doc_base else base_url
    else:
        eff_base = base_url

    # Remove nodes
    if remove_sels:
        remove_matching(document, remove_sels)

    # Find matches
    all_selectors = _split_comma(selector_str)
    results = []
    seen = set()
    for sel in all_selectors:
        matches = _find_compound(document, sel)
        for m in matches:
            if m not in seen:
                seen.add(m)
                results.append(m)

    # Build output
    output_lines = []
    for node in results:
        if text_flag:
            output_lines.append(extract_text(node, ignore_ws))
        elif attr_name:
            val = get_attr(node, attr_name)
