#!/usr/bin/env python3
"""htmlq - A command-line utility for querying HTML documents with CSS selectors."""

import sys
import os
import re
from html.parser import HTMLParser
from html import entities
from urllib.parse import urljoin

VERSION_STR = "htmlq 0.4.0"


# ─────────────────────── DOM Node ───────────────────────

class Node:
    # NOTE: can't use __slots__ because we need to add _order dynamically
    __slots__ = ("tag", "attrs", "children", "text", "parent", "_order")

    def __init__(self, tag=None, attrs=None, text=None):
        self.tag = tag          # None for text nodes
        self.attrs = attrs or []   # list of (name, value) tuples
        self.children = []
        self.text = text        # only for text nodes
        self.parent = None
        self._order = 0

    def is_element(self):
        return self.tag is not None


# ─────────────────────── HTML Parser ───────────────────────

BLOCK_ELEMENTS = {
    "address", "article", "aside", "blockquote", "br", "caption", "dd", "details",
    "dialog", "div", "dl", "dt", "fieldset", "figcaption", "figure", "footer", "form",
    "h1", "h2", "h3", "h4", "h5", "h6", "header", "hgroup", "hr", "legend", "li",
    "main", "menu", "nav", "ol", "p", "pre", "section", "summary", "table", "tbody",
    "td", "tfoot", "th", "thead", "tr", "ul",
}

HTML_VOID_ELEMENTS = {
    "area", "base", "br", "col", "embed", "hr", "img", "input",
    "link", "meta", "param", "source", "track", "wbr",
}

AUTO_CLOSE_IN = {
    "li": ("li",),
    "optgroup": ("optgroup",),
    "option": ("option", "optgroup"),
    "tr": ("th", "td", "tr"),
    "td": ("td", "th"),
    "th": ("td", "th"),
    "dt": ("dt", "dd"),
    "dd": ("dt", "dd"),
    "p": ("p",),
    "rp": ("rp", "rt"),
    "rt": ("rp", "rt"),
}


class DOMBuilder(HTMLParser):
    """Parse HTML into a tree of Node objects."""
    def __init__(self):
        super().__init__(convert_charrefs=True)
        self.root = Node(tag="__root__")
        self.current = self.root
        self.stack = []  # stack of (tag, node)

    def _add_child(self, node):
        self.current.children.append(node)
        node.parent = self.current

    def handle_starttag(self, tag, attrs):
        tag = tag.lower()
        self._auto_close(tag)
        node = Node(tag=tag, attrs=list(attrs))
        self._add_child(node)
        if tag not in HTML_VOID_ELEMENTS:
            self.stack.append((tag, node))
            self.current = node

    def _auto_close(self, tag):
        """Auto-close parents that can't contain this tag."""
        if tag in AUTO_CLOSE_IN:
            close_tags = AUTO_CLOSE_IN[tag]
            while self.stack:
                top_tag = self.stack[-1][0]
                if top_tag in close_tags:
                    self.stack.pop()
                    self.current = self.stack[-1][1] if self.stack else self.root
                else:
                    break

    def handle_endtag(self, tag):
        tag = tag.lower()
        # Pop stack until we find matching tag
        while self.stack:
            top_tag, _ = self.stack[-1]
            if top_tag == tag:
                self.stack.pop()
                self.current = self.stack[-1][1] if self.stack else self.root
                return
            self.stack.pop()
            self.current = self.stack[-1][1] if self.stack else self.root

    def handle_data(self, data):
        node = Node(text=data)
        self._add_child(node)

    def handle_entityref(self, name):
        char = entities.html5.get(name, f"&{name};")
        node = Node(text=char)
        self._add_child(node)

    def handle_charref(self, name):
        try:
            if name.startswith("x") or name.startswith("X"):
                code = int(name[1:], 16)
            else:
                code = int(name)
            char = chr(code)
        except Exception:
            char = f"&#{name};"
        node = Node(text=char)
        self._add_child(node)

    def handle_comment(self, data):
        pass

    def handle_decl(self, decl):
        pass

    def handle_pi(self, data):
        pass


def parse_html(html_str):
    builder = DOMBuilder()
    try:
        builder.feed(html_str)
    except Exception:
        pass
    return builder.root


# ─────────────────────── Force HTML structure (head+body) ───────────────────────

def force_html_structure(document):
    """Wrap root's children in proper html/head/body structure."""
    # For the root document, we expect children to be html and its contents
    # We need to normalize to have head+body inside html
    root_children = document.children
    if not root_children:
        return document

    # Flatten to find html tag
    html_node = None
    for c in root_children:
        if c.is_element() and c.tag == "html":
            html_node = c
            break

    if html_node is None:
        # No html tag - create one
        html_node = Node(tag="html")
        html_node.parent = document
        document.children = [html_node]
        # Move all root children as html children
        html_node.children.extend(root_children)
        for c in root_children:
            c.parent = html_node

    # Ensure head exists
    head_node = None
    body_node = None
    for c in html_node.children:
        if c.is_element():
            if c.tag == "head" and head_node is None:
                head_node = c
            elif c.tag == "body" and body_node is None:
                body_node = c

    if head_node is None:
        # Insert empty head before body (or before first child)
        empty_head = Node(tag="head")
        head_node = empty_head
        head_node.parent = html_node
        if body_node:
            idx = html_node.children.index(body_node)
            html_node.children.insert(idx, empty_head)
        else:
            html_node.children.insert(0, empty_head)

    # Ensure body exists
    if body_node is None:
        empty_body = Node(tag="body")
        body_node = empty_body
        body_node.parent = html_node
        html_node.children.append(empty_body)

    return document


# ─────────────────────── CSS Selector Engine ───────────────────────

class SimpleSelector:
    """A simple selector (tag + ids + classes + attr predicates)."""
    def __init__(self):
        self.tag = None
        self.ids = set()
        self.classes = set()
        self.attr_checks = []
        self.is_universal = False

    def match(self, node):
        if not node.is_element():
            return False

        # Check tag
        if self.tag is not None:
            ntag = node.tag.lower()
            if self.tag != ntag:
                return False

        # Check ids
        if self.ids:
            node_id = None
            for k, v in node.attrs:
                if k.lower() == "id":
                    node_id = v.lower()
                    break
            if node_id is None or not self.ids.issubset({node_id}):
                return False

        # Check classes
        if self.classes:
            node_classes = set()
            for k, v in node.attrs:
                if k.lower() == "class" and v:
                    node_classes.update(tc.strip().lower() for tc in v.split() if tc.strip())
            if not self.classes.issubset(node_classes):
                return False

        # Check attribute selectors
        for check in self.attr_checks:
            cname = check[0]
            if len(check) == 1:
                # Existence check
                if not any(k.lower() == cname for k, _ in node.attrs):
                    return False
                continue
            op = check[1]
            val = check[2]
            casei = check[3] if len(check) > 3 else False
            aval = None
            for k, v in node.attrs:
                if k.lower() == cname:
                    aval = v
                    break
            if aval is None:
                if op != "!=":
                    return False
                continue
            if casei:
                aval = aval.lower()
                val = val.lower()
            if op == "=" and aval != val:
                return False
            elif op == "~=" and val not in aval.split():
                return False
            elif op == "|=" and (aval != val and not aval.startswith(val + "-")):
                return False
            elif op == "^=" and not aval.startswith(val):
                return False
            elif op == "$=" and not aval.endswith(val):
                return False
            elif op == "*=" and val not in aval:
                return False
            elif op == "!=" and aval == val:
                return False

        return True


def _tokenize_attr(s):
    s = s.strip()
    if not s:
        return None, None, None, False
    case_insensitive = False
    if s.endswith(' i'):
        case_insensitive = True
        s = s[:-2].strip()
    elif s.endswith(' I'):
        case_insensitive = True
        s = s[:-2].strip()
    for op in ['~=', '|=', '!=', '^=', '$=', '*=', '=']:
        idx = s.find(op)
        if idx >= 0:
            name = s[:idx].strip().lower()
            raw_val = s[idx + len(op):].strip()
            raw_val = raw_val.strip()
            if len(raw_val) >= 2 and (
                (raw_val[0] == '"' and raw_val[-1] == '"') or
                (raw_val[0] == "'" and raw_val[-1] == "'")
            ):
                raw_val = raw_val[1:-1]
            return name, op, raw_val, case_insensitive
    return s.strip().lower(), None, None, False


def parse_simple_selector(token):
    ss = SimpleSelector()
    s = token
    i = 0
    while i < len(s):
        c = s[i]
        if c == '#':
            j = i + 1
            while j < len(s) and (s[j].isalnum() or s[j] in '-_@'):
                j += 1
            if j > i + 1:
                ss.ids.add(s[i+1:j].lower())
            i = j
        elif c == '.':
            j = i + 1
            while j < len(s) and (s[j].isalnum() or s[j] in '-_@'):
                j += 1
            if j > i + 1:
                ss.classes.add(s[i+1:j].lower())
            i = j
        elif c == '[':
            depth = 1
            j = i + 1
            while j < len(s) and depth > 0:
                if s[j] == '[': depth += 1
                elif s[j] == ']': depth -= 1
                j += 1
            inner = s[i+1:j-1]
            name, op, val, casei = _tokenize_attr(inner)
            if op is not None:
                ss.attr_checks.append((name, op, val, casei))
            else:
                ss.attr_checks.append((name,))
            i = j
        elif c == '*':
            ss.is_universal = True
            i += 1
        elif c in '.@' or c.isalnum():
            j = i
            while j < len(s) and (s[j].isalnum() or s[j] in '-_@'):
                j += 1
            part = s[i:j]
            if ss.tag is None:
                ss.tag = part.lower()
            i = j
        else:
            i += 1
    return ss


def find_all_matching(document, ss):
    results = []
    def walk(node):
        if node.is_element() and ss.match(node):
            results.append(node)
        for child in node.children:
            walk(child)
    walk(document)
    return results


def _split_comma(s):
    parts = []
    depth = 0
    buf = []
    in_sq = in_dq = False
    for i, c in enumerate(s):
        if c == '"' and not in_sq: in_dq = not in_dq
        elif c == "'" and not in_dq: in_sq = not in_sq
        elif not in_sq and not in_dq:
            if c in '([{': depth += 1
            elif c in ')]}': depth -= 1
            elif c == ',' and depth == 0:
                parts.append(''.join(buf).strip())
                buf = []
                continue
        buf.append(c)
    rest = ''.join(buf).strip()
    if rest:
        parts.append(rest)
    return parts


def _parse_compound(part):
    tokens = []
    depth = 0
    buf = []
    in_sq = in_dq = False
    for c in part:
        if c == '"' and not in_sq: in_dq = not in_dq
        elif c == "'" and not in_dq: in_sq = not in_sq
        elif not in_sq and not in_dq:
            if c in '([{': depth += 1
            elif c in ')]}': depth -= 1
            elif c == ' ' and depth == 0:
                t = ''.join(buf).strip()
                if t:
                    tokens.append(t)
                buf = []
                continue
        buf.append(c)
    t = ''.join(buf).strip()
    if t:
        tokens.append(t)
    return [parse_simple_selector(tok) for tok in tokens]


def _find_compound(document, compound_str):
    sels = _parse_compound(compound_str)
    if not sels:
        return []
    if len(sels) == 1:
        return find_all_matching(document, sels[0])

    matches_first = find_all_matching(document, sels[0])
    results = []
    for m in matches_first:
        results.extend(_descendant_find(m, sels[1:]))
    return results


def _descendant_find(ancestor, remaining_sels):
    if not remaining_sels:
        return [ancestor]
    ss = remaining_sels[0]
    results = []
    for child in ancestor.children:
        if child.is_element() and ss.match(child):
            if len(remaining_sels) == 1:
                results.append(child)
            else:
                results.extend(_descendant_find(child, remaining_sels[1:]))
    return results


# ─────────────────────── Global order assignment ───────────────────────

_doc_order_counter = [0]

def assign_orders(node):
    _assign_orders(node, _doc_order_counter)

def _assign_orders(node, counter):
    if node.is_element():
        node._order = counter[0]
        counter[0] += 1
    for child in node.children:
        _assign_orders(child, counter)


# ─────────────────────── Serialization ───────────────────────

esc_table = str.maketrans({
    '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&apos;'
})

def html_escape(text):
    return text.translate(esc_table)


def serialize(node, pretty=False):
    if not node.is_element():
        if node.text is not None:
            return html_escape(node.text)
        return ""

    tag = node.tag
    attrs_str = ""
    for k, v in node.attrs:
        if v is None:
            attrs_str += " " + k
        else:
            attrs_str += ' {}="{}"'.format(k, html_escape(str(v)))

    if tag in HTML_VOID_ELEMENTS:
        return "<{}{}>".format(tag, attrs_str)

    children_out = ""
    for child in node.children:
        children_out += serialize(child, pretty)

    if pretty:
        return _serialize_pretty(tag, attrs_str, children_out, 0)
    return "<{}{}{}>{}</{}>".format(tag, attrs_str, "", children_out, tag)


def _serialize_pretty(tag, attrs_str, children_out, indent_level):
    indent = "  " * indent_level

    if tag in BLOCK_ELEMENTS:
        if indent_level > 0:
            pre = "{}".format(indent)
        else:
            pre = ""

        if children_out.strip():
            return "{}<{}{}>\n{}{}\n{}{}</{}>".format(
                pre, tag, attrs_str, indent, children_out,
                pre, tag)
        else:
            return "{}<{}{}</{}>".format(pre, tag, attrs_str, tag)
    else:
        return "<{}{}{}>{}</{}>".format(tag, attrs_str, "", children_out, tag)


# ─────────────────────── Text extraction ───────────────────────

def extract_text(node, ignore_ws=False):
    parts = []
    for child in node.children:
        if child.is_element():
            parts.append(extract_text(child, ignore_ws))
        else:
            t = child.text if child.text else ""
            if ignore_ws and not t.strip():
                continue
            parts.append(t)
    return ''.join(parts)


# ─────────────────────── Attribute ───────────────────────

def get_attr(node, name):
    name_lower = name.lower()
    for k, v in node.attrs:
        if k.lower() == name_lower:
            return v
    return None


# ─────────────────────── Base URL ───────────────────────

def find_base(document):
    def walk(node):
        if not node.is_element():
            return None
        if node.tag == 'base':
            for k, v in node.attrs:
                if k.lower() == 'href' and v:
                    return v
        for child in node.children:
            r = walk(child)
            if r:
                return r
        return None
    return walk(document)


def resolve_url(base, href):
    if base:
        return urljoin(base, href)
    return href


# ─────────────────────── Remove nodes ───────────────────────

def remove_tree_matching(document, remove_selector_strs):
    for sel_str in remove_selector_strs:
        comma_parts = _split_comma(sel_str)
        for cp in comma_parts:
            matches = _find_compound(document, cp.strip())
            for m in matches:
                if m.parent:
                    m.parent.children = [
                        c for c in m.parent.children if c is not m
                    ]


# ─────────────────────── Main ───────────────────────

def main():
    pid = os.getpid()
    pgm = sys.argv[0] if sys.argv else "htmlq"

    args = sys.argv[1:]

    selectors = []
    text_flag = False
    pretty_flag = False
    ignore_ws = False
    detect_base = False
    attr_name = None
    base_url = None
    filename = None
    output_file = None
    remove_sels = []

    i = 0
    while i < len(args):
        a = args[i]
        if a in ('-h', '--help'):
            _print_help(pgm)
            sys.exit(0)
        elif a in ('-V', '--version'):
            print(VERSION_STR)
            sys.exit(0)
        elif a in ('-t', '--text'):
            text_flag = True
        elif a in ('-p', '--pretty'):
            pretty_flag = True
        elif a in ('-w', '--ignore-whitespace'):
            ignore_ws = True
        elif a in ('-B', '--detect-base'):
            detect_base = True
        elif a in ('-a', '--attribute'):
            i += 1
            attr_name = args[i]
        elif a in ('-b', '--base'):
            i += 1
            base_url = args[i]
        elif a in ('-f', '--filename'):
            i += 1
            filename = args[i]
        elif a in ('-o', '--output'):
            i += 1
            output_file = args[i]
        elif a in ('-r', '--remove-nodes'):
            i += 1
            remove_sels.append(args[i])
        elif a == '--':
            i += 1
            selectors.extend(args[i:])
            break
        else:
            selectors.append(a)
        i += 1

    if not selectors:
        selector_str = "html"
    else:
        selector_str = ", ".join(selectors)

    # Read input
    if filename:
        try:
            with open(filename, 'r') as f:
                html_str = f.read()
        except OSError as e:
            sys.stderr.write(
                "\nthread 'main' ({0}) panicked at src/main.rs:196:37:\n"
                "should have opened input file: {1}\n"
                "note: run with `RUST_BACKTRACE=1` environment variable to display a backtrace\n"
                .format(e)
            )
            sys.exit(101)
    else:
        html_str = sys.stdin.read()

    # Parse
    document = parse_html(html_str)
    _doc_order_counter[0] = 0
    assign_orders(document)

    # Normalize HTML structure (auto-insert head/body)
    force_html_structure(document)
    _doc_order_counter[0] = 0
    assign_orders(document)

    # Detect base URL
    if detect_base:
        doc_base = find_base(document)
        eff_base = doc_base if doc_base else base_url
    else:
        eff_base = base_url

    # Remove nodes
    if remove_sels:
        remove_tree_matching(document, remove_sels)

    # Find matching elements
    all_selectors = _split_comma(selector_str)
    results = []
    seen_ids = set()
    for sel in all_selectors:
        matches = _find_compound(document, sel)
        for m in matches:
            oid = id(m)
            if oid not in seen_ids:
                seen_ids.add(oid)
                results.append(m)

    results.sort(key=lambda n: n._order)

    # Build output
    output_lines = []
    for node in results:
        if text_flag:
            output_lines.append(extract_text(node, ignore_ws))
        elif attr_name:
            val = get_attr(node, attr_name)
            if val is not None:
                if eff_base and attr_name:
                    val = resolve_url(eff_base, val)
                output_lines.append(val)
        else:
            output_lines.append(serialize(node, pretty_flag))

    out = '\n'.join(output_lines)
    if out:
        out += '\n'

    if output_file:
        with open(output_file, 'w') as f:
            f.write(out)
    else:
        sys.stdout.write(out)


def _print_help(prog):
    print("""htmlq 0.4.0
Michael Maclean <michael@mgdm.net>
Runs CSS selectors on HTML

USAGE:
