# ─── CSS Selector Engine ───

class SimpleSelector:
    def __init__(self):
        self.tag = None
        self.ids = set()
        self.classes = set()
        self.attr_checks = []
        self.is_universal = False

    def match(self, node):
        if not node.is_element():
            return False
        if self.tag is not None and self.tag != node.tag.lower():
            return False
        if self.ids:
            nid = None
            for k, v in node.attrs:
                if k.lower() == "id":
                    nid = v.lower()
                    break
            if nid is None or not self.ids.issubset({nid}):
                return False
        if self.classes:
            nc = set()
            for k, v in node.attrs:
                if k.lower() == "class" and v:
                    nc.update(tc.strip().lower() for tc in v.split() if tc.strip())
            if not self.classes.issubset(nc):
                return False
        for check in self.attr_checks:
            cname = check[0]
            if len(check) == 1:
                if not any(k.lower() == cname for k, _ in node.attrs):
                    return False
                continue
            op, val, ci = check[1], check[2], check[3] if len(check) > 3 else False
            aval = None
            for k, v in node.attrs:
                if k.lower() == cname:
                    aval = v
                    break
            if aval is None:
                if op != "!=":
                    return False
                continue
            if ci:
                aval = aval.lower()
                val = val.lower()
            if op == "=" and aval != val: return False
            if op == "~=" and val not in aval.split(): return False
            if op == "|=" and aval != val and not aval.startswith(val + "-"): return False
            if op == "^=" and not aval.startswith(val): return False
            if op == "$=" and not aval.endswith(val): return False
            if op == "*=" and val not in aval: return False
            if op == "!=" and aval == val: return False
        return True

def _tokenize_attr(s):
    s = s.strip()
    if not s:
        return None, None, None, False
    ci = False
    if s.endswith(' i'):
        ci = True
        s = s[:-2].strip()
    elif s.endswith(' I'):
        ci = True
        s = s[:-2].strip()
    for op in ['~=', '|=', '!=', '^=', '$=', '*=', '=']:
        idx = s.find(op)
        if idx >= 0:
            name = s[:idx].strip().lower()
            raw = s[idx + len(op):].strip()
            if len(raw) >= 2 and raw[0] in ('"', "'") and raw[0] == raw[-1]:
                raw = raw[1:-1]
            return name, op, raw, ci
    return s.strip().lower(), None, None, False

def parse_simple_selector(token):
    ss = SimpleSelector()
