    "link", "meta", "param", "source", "track", "wbr",
}

AUTO_CLOSE_IN = {
    "li": ("li",),
    "optgroup": ("optgroup",),
    "option": ("option", "optgroup"),
    "tr": ("th", "td", "tr"),
    "td": ("td", "th"),
    "th": ("td", "th"),
    "dt": ("dt", "dd"),
    "dd": ("dt", "dd"),
    "p": ("p",),
    "rp": ("rp", "rt"),
    "rt": ("rp", "rt"),
}

class DOMBuilder(HTMLParser):
    def __init__(self):
        super().__init__(convert_charrefs=True)
        self.root = Node(tag="__root__")
        self.current = self.root
        self.stack = []

    def _add_child(self, node):
        self.current.children.append(node)
        node.parent = self.current

    def handle_starttag(self, tag, attrs):
        tag = tag.lower()
        self._auto_close(tag)
        node = Node(tag=tag, attrs=list(attrs))
        self._add_child(node)
        if tag not in HTML_VOID_ELEMENTS:
            self.stack.append((tag, node))
            self.current = node

    def _auto_close(self, tag):
        if tag in AUTO_CLOSE_IN:
            close_tags = AUTO_CLOSE_IN[tag]
            while self.stack:
                top_tag = self.stack[-1][0]
                if top_tag in close_tags:
                    self.stack.pop()
                    if self.stack:
                        self.current = self.stack[-1][1]
                    else:
                        self.current = self.root
                else:
                    break

    def handle_endtag(self, tag):
        tag = tag.lower()
        while self.stack:
            top_tag, _ = self.stack[-1]
            if top_tag == tag:
                self.stack.pop()
                if self.stack:
                    self.current = self.stack[-1][1]
                else:
                    self.current = self.root
                return
            self.stack.pop()
            if self.stack:
                self.current = self.stack[-1][1]
            else:
                self.current = self.root

    def handle_data(self, data):
        self._add_child(Node(text=data))

    def handle_entityref(self, name):
        self._add_child(Node(text=entities.html5.get(name, f"&{name};")))

    def handle_charref(self, name):
        try:
            if name.lower().startswith("x"):
                code = int(name[1:], 16)
            else:
                code = int(name)
            self._add_child(Node(text=chr(code)))
        except Exception:
            self._add_child(Node(text=f"&#{name};"))

    def handle_comment(self, data): pass
    def handle_decl(self, decl): pass
    def handle_pi(self, data): pass

