        document.children = [html_node]
        for c in rc: c.parent = html_node
        html_node.children.extend(rc)
    head_node = body_node = None
    for c in html_node.children:
        if c.is_element():
            if c.tag == "head" and head_node is None: head_node = c
            elif c.tag == "body" and body_node is None: body_node = c
