    return result

def split_comma(s):
    parts, depth, buf, in_sq, in_dq = [], 0, [], False, False
    for c in s:
        if c == '"' and not in_sq: in_dq = not in_dq
        elif c == "'" and not in_dq: in_sq = not in_sq
        elif not in_sq and not in_dq:
            if c in '([{': depth += 1
            elif c in ')]}': depth -= 1
            elif c == ',' and depth == 0:
                r = ''.join(buf).strip()
                if r: parts.append(r)
                buf = []; continue
        buf.append(c)
    r = ''.join(buf).strip()
    if r: parts.append(r)
    return parts

def split_compound(part):
    tokens, depth, buf, in_sq, in_dq = [], 0, [], False, False
    for c in part:
        if c == '"' and not in_sq: in_dq = not in_dq
        elif c == "'" and not in_dq: in_sq = not in_sq
        elif not in_sq and not in_dq:
            if c in '([{': depth += 1
            elif c in ')]}': depth -= 1
            elif c == ' ' and depth == 0:
                t = ''.join(buf).strip()
                if t: tokens.append(t)
                buf = []; continue
        buf.append(c)
    t = ''.join(buf).strip()
    if t: tokens.append(t)
    return [parse_simple_selector(tok) for tok in tokens]

